FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("กรุณารอ %d วินาทีก่อนส่งอีกครั้ง", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
