task.spawn(function()
    safeSet(statusLabel, "กำลังยืนยันตัวตน...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "สถานะ: ล้มเหลว")
        Library:Notify({Title="COMBOWICK", Description="การตรวจสอบเซสชันล้มเหลว", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ เกมถูกปิดใช้งาน")
            safeSet(hintLabel, "เวอร์ชันฟรีใช้ไม่ได้ที่นี่ กรุณารับคีย์")
            Library:Notify({Title="COMBOWICK", Description="เวอร์ชันฟรีถูกปิดใช้งานสำหรับเกมนี้ กรุณาใช้คีย์", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "สถานะ: ล้มเหลว")
        else
            safeSet(statusLabel, "สถานะ: ยืนยันตัวตนแล้ว")
            Library:Notify({Title="COMBOWICK", Description="คุณยืนยันตัวตนแล้ว", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("เวลาที่เหลือ: %s", fmt))
                    safeSet(lSession, string.format("เวลาเซสชัน: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "เซสชันหมดอายุแล้ว")
                safeSet(lSession, "เวลาเซสชัน: หมดอายุ")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "อยู่ในช่วงคูลดาวน์")
        safeSet(hintLabel, "รับคีย์ 11 ชั่วโมง หรือรอให้คูลดาวน์สิ้นสุด")
        Library:Notify({Title="COMBOWICK", Description="คุณอยู่ในช่วงคูลดาวน์ รับคีย์เพื่อข้ามการรอ", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("คูลดาวน์: %s", fmt))
                safeSet(lCooldown, string.format("คูลดาวน์: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "คูลดาวน์สิ้นสุดแล้ว")
            safeSet(lCooldown, "คูลดาวน์: สิ้นสุดแล้ว")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="คูลดาวน์สิ้นสุดแล้ว กำลังโหลดใหม่...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "คำขอมากเกินไป")
        safeSet(hintLabel, "คำขอมากเกินไป กรุณารอ")
        Library:Notify({Title="COMBOWICK", Description="คำขอมากเกินไป กรุณารอสักครู่", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("ลองใหม่ใน %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "กำลังโหลดใหม่...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "บริการหยุดชั่วคราว")
        safeSet(hintLabel, "COMBOWICK ออฟไลน์ชั่วคราว")
        Library:Notify({Title="COMBOWICK", Description="ขณะนี้บริการถูกปิดใช้งาน กรุณาลองใหม่ภายหลัง", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "ถูกแบน")
        Library:Notify({Title="COMBOWICK", Description="คุณถูกแบน", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 ไม่รองรับเกมนี้")
        safeSet(hintLabel, "ยังไม่รองรับเกมนี้ คีย์ Premium ยังใช้ได้หากมีสคริปต์")
        Library:Notify({Title="COMBOWICK", Description="ยังไม่รองรับเกมนี้", Time=6})

